t.script:
// If a screenshot file is missing, swap the broken
// image with a soft placeholder so the page still
// looks tidy until real screenshots are dropped in.
(function() {
    document.addEventListener('DOMContentLoaded', function() {
        document.querySelectorAll('.docs-figure img').forEach(function(img) {
            img.addEventListener('error', function() {
                var placeholder = document.createElement('div');
                placeholder.className = 'docs-figure-placeholder';
                placeholder.innerHTML = (
                    '' +
                    'Screenshot will appear here' +
                    '' +
                    (img.alt || '') + ''
                );
                img.replaceWith(placeholder);
            });
        });
    });
})();
